# Eiros Configuration Guide

## Hardware Config Format

Hardware configurations are Nix flakes that export a `nixosModules.default` module. This module sets hardware-specific options under the `eiros.system.hardware.*` namespace.

**Example structure:**
```nix
# flake.nix in your hardware repo
{
  outputs = { nixpkgs, ... }: {
    nixosModules.default = { ... }: {
      eiros.system.hardware.cpu.vendor = "amd";
      eiros.system.hardware.graphics.nvidia.enable = true;
    };
  };
}
```

**Available hardware options include:**
- CPU vendor selection
- GPU configuration (NVIDIA with PRIME offload/sync support)
- Power management
- Peripherals (Bluetooth, printing, fingerprint)
- Memory management (zram compressed swap with algorithm and percentage settings)

## User Config Format

User configurations are Nix flakes exporting `nixosModules.default` that configure accounts and personalization under `eiros.users.*`.

**Example structure:**
```nix
# flake.nix in your users repo
{
  outputs = { nixpkgs, ... }: {
    nixosModules.default = { ... }: {
      eiros.users.yourusername = {
        initial_password = "change_me";
        dms.settings = { /* DMS overrides */ };
        mangowc = { /* MangoWC settings, keybinds, wallpaper */ };
      };
    };
  };
}
```

**User-level configuration covers:**
- Account creation with initial password
- "Per-user DMS settings override" for desktop shell customization
- MangoWC keybinds and wallpaper assignment
- Integration with system-wide defaults

## File Placement & Structure

The core Eiros repository organizes configurations hierarchically:

- **`system/`** — System-level module schemas (audio, boot, applications, desktop environment, hardware, networking, security, virtualization)
- **`users/default_settings/`** — System-wide user defaults for DMS and MangoWC
- **`users/users.nix`** — User account module schema
- **`resources/nix/`** — Module loading utilities and helper functions

Hardware and user repos remain separate and are injected via `--override-input` during builds, maintaining modularity and avoiding coupling between configurations.

{
  description = "Eiros: A NixOS configuration using MangoWC";

  outputs =
    {
      dank_material_shell,
      dms_docker_manager,
      dms_ssh_connections,
      wallpaper_carousel,
      eiros_hardware,
      eiros_users,
      hjem,
      mango,
      nix-alien,
      nix-index-database,
      nixpkgs,
      nvf,
      sops-nix,
      self,
      ...
    }:
    let
      inputs = {
        inherit
          dank_material_shell
          dms_docker_manager
          dms_ssh_connections
          wallpaper_carousel
          eiros_hardware
          eiros_users
          hjem
          mango
          nix-alien
          nix-index-database
          nixpkgs
          nvf
          sops-nix
          ;
      };

      import_modules = import ./resources/nix/import_modules.nix;
    in
    {
      nixosConfigurations.default = nixpkgs.lib.nixosSystem {
        modules = [
          dank_material_shell.nixosModules.dank-material-shell
          dank_material_shell.nixosModules.greeter
          eiros_hardware.nixosModules.default
          eiros_users.nixosModules.default
          hjem.nixosModules.default
          mango.nixosModules.mango
          nix-index-database.nixosModules.default
          nvf.nixosModules.default
          sops-nix.nixosModules.sops
          { nixpkgs.overlays = [ nix-alien.overlays.default ]; }
        ]
        ++ (import_modules ./system)
        ++ (import_modules ./users);

        specialArgs = { inherit inputs; };
      };
    };

  inputs = {
    dank_material_shell = {
      url = "github:AvengeMedia/DankMaterialShell";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    dms_docker_manager = {
      url = "github:LuckShiba/DmsDockerManager";
      flake = false;
    };

    dms_ssh_connections = {
      url = "github:merdely/dms-plugins";
      flake = false;
    };

    wallpaper_carousel = {
      url = "github:motor-dev/wallpaperCarousel";
      flake = false;
    };

    eiros_hardware = {
      url = "github:lcleveland/eiros.hardware";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    eiros_users = {
      url = "github:lcleveland/eiros.users";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    hjem = {
      url = "github:feel-co/hjem";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    mango = {
      url = "github:DreamMaoMao/mango";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    nix-alien = {
      url = "github:thiagokokada/nix-alien";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    nix-index-database = {
      url = "github:nix-community/nix-index-database";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    nixpkgs.url = "github:nixos/nixpkgs/nixos-unstable";

    nvf = {
      url = "github:notashelf/nvf";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    sops-nix = {
      url = "github:Mic92/sops-nix";
      inputs.nixpkgs.follows = "nixpkgs";
    };

  };
}

# Declares per-user accounts, groups, and MangoWC home configurations managed via hjem.
{ config, lib, ... }:

let
  helpers = import ../resources/nix/mangowc_helpers.nix lib;
  inherit (helpers) mangowc_generator make_mangowc_config keybind_submodule;

  default_keybinds = config.eiros.system.user_defaults.mangowc.keybinds;

  # Merges system default keybinds with per-user overrides, then injects systemd env-import
  # and DMS exec-once entries so MangoWC starts with the correct session environment.
  make_user_mangowc_config =
    mangowc_cfg:
    let
      effective_keybinds =
        (lib.optionalAttrs mangowc_cfg.default_keybinds.enable default_keybinds) // mangowc_cfg.keybinds;
      effective_cfg = mangowc_cfg // {
        keybinds = effective_keybinds;
      };

      mangowc_systemd = config.eiros.system.desktop_environment.mangowc.systemd;
      vars_str = lib.concatStringsSep " " mangowc_systemd.variables;

      base = make_mangowc_config effective_cfg;

      extra_exec_once =
        (lib.optionals (config.eiros.system.desktop_environment.mangowc.enable && mangowc_systemd.enable) [
          "systemctl --user import-environment ${vars_str}"
          "dbus-update-activation-environment --systemd ${vars_str}"
          "sh -c 'systemctl --user set-environment GNOME_KEYRING_CONTROL=/run/user/$(id -u)/keyring && dbus-update-activation-environment --systemd GNOME_KEYRING_CONTROL'"
        ])
        ++ (lib.optionals config.eiros.system.desktop_environment.dankmaterialshell.enable [
          (
            let
              dms_wait = config.eiros.system.desktop_environment.dankmaterialshell.wait_for_network;
            in
            if dms_wait.enable
            then "sh -c 'nm-online -q -t ${toString dms_wait.timeout}; dms run'"
            else "dms run"
          )
          "udiskie &"
        ])
        ++ (lib.optional (
          mangowc_cfg.wallpaper != null
        ) "dms ipc call wallpaper set ${mangowc_cfg.wallpaper}");
    in
    base
    // {
      "exec-once" = (base."exec-once" or [ ]) ++ extra_exec_once;
    };
in
{
  options = {
    eiros.users = lib.mkOption {
      default = { };
      description = "Per-user configuration for the eiros system, including MangoWC and home management.";
      example = lib.literalExpression ''
        {
          eiros.users = {
            alice = {
              extra_groups = [ "wheel" "audio" ];
              mangowc = {
                wallpaper = /home/alice/wallpaper.jpg;
                keybinds = {
                  open_browser = {
                    modifier_keys = [ "SUPER" ];
                    key_symbol = "b";
                    mangowc_command = "spawn";
                    command_arguments = "vivaldi";
                  };
                };
              };
            };
          };
        }
      '';
      type = lib.types.attrsOf (
        lib.types.submodule (
          { name, ... }:
          {
            options = {
              extra_groups = lib.mkOption {
                default = [
                  "wheel"
                  "networkmanager"
                  "libvirtd"
                ];
                description = "Additional groups for the user.";
                example = lib.literalExpression ''
                  {
                    eiros.users.alice.extra_groups = [ "wheel" "audio" "video" ];
                  }
                '';
                type = lib.types.listOf lib.types.str;
              };

              initial_password = lib.mkOption {
                default = name;
                description = "Initial password for the user. WARNING: defaults to the username — change this before deploying to a real system.";
                example = lib.literalExpression ''
                  {
                    eiros.users.alice.initial_password = "changeme";
                  }
                '';
                type = lib.types.str;
              };

              dms = lib.mkOption {
                default = { };
                description = "Per-user DMS settings written to ~/.config/DankMaterialShell/settings.json (or null to skip). Defaults to the system-wide eiros.system.user_defaults.dms settings.";
                example = lib.literalExpression ''
                  {
                    eiros.users.alice.dms = {
                      settings = {
                        currentThemeName = "blue";
                        cornerRadius = 12;
                        use24HourClock = false;
                      };
                    };
                  }
                '';
                type = lib.types.nullOr (
                  lib.types.submodule {
                    options = {
                      clobber = lib.mkOption {
                        default = true;
                        description = "Whether hjem is allowed to overwrite an existing settings.json.";
                        example = lib.literalExpression ''
                          {
                            eiros.users.alice.dms.clobber = false;
                          }
                        '';
                        type = lib.types.bool;
                      };

                      settings = lib.mkOption {
                        default = config.eiros.system.user_defaults.dms._settings;
                        description = "DMS settings attribute set serialised to JSON. Override individual keys to deviate from the system-wide defaults in eiros.system.user_defaults.dms.";
                        example = lib.literalExpression ''
                          {
                            eiros.users.alice.dms.settings = {
                              currentThemeName = "blue";
                              cornerRadius = 8;
                            };
                          }
                        '';
                        type = lib.types.attrsOf lib.types.anything;
                      };

                      plugin_settings = lib.mkOption {
                        default = config.eiros.system.user_defaults.dms.misc.external_plugin_settings;
                        description = "External plugin settings written to plugin_settings.json. Defaults to the system-wide external_plugin_settings.";
                        type = lib.types.attrsOf lib.types.anything;
                      };
                    };
                  }
                );
              };

              mangowc = lib.mkOption {
                default = null;
                description = "Per-user MangoWC configuration (or null if unused).";
                example = lib.literalExpression ''
                  {
                    eiros.users.alice.mangowc = {
                      wallpaper = /home/alice/wallpaper.png;
                      settings = { border_width = 2; };
                    };
                  }
                '';
                type = lib.types.nullOr (
                  lib.types.submodule {
                    options = {
                      clobber_home_directory = lib.mkOption {
                        default = true;
                        description = "Whether hjem is allowed to clobber the existing home directory.";
                        example = lib.literalExpression ''
                          {
                            eiros.users.alice.mangowc.clobber_home_directory = false;
                          }
                        '';
                        type = lib.types.bool;
                      };

                      default_keybinds.enable = lib.mkOption {
                        default = true;
                        description = "Apply the Eiros default MangoWC keybinds. User keybinds with matching names override the defaults.";
                        example = lib.literalExpression ''
                          {
                            eiros.users.alice.mangowc.default_keybinds.enable = false;
                          }
                        '';
                        type = lib.types.bool;
                      };

                      wallpaper = lib.mkOption {
                        default = null;
                        description = "Absolute path to the wallpaper image. When set, runs `dms ipc call wallpaper set <path>` on login.";
                        example = lib.literalExpression ''
                          {
                            eiros.users.alice.mangowc.wallpaper = /home/alice/wallpaper.png;
                          }
                        '';
                        type = lib.types.nullOr lib.types.path;
                      };

                      keybinds = lib.mkOption {
                        default = { };
                        description = "Structured MangoWC keybind declarations. Keys matching a default keybind name override that default.";
                        example = lib.literalExpression ''
                          {
                            eiros.users.alice.mangowc.keybinds = {
                              open_browser = {
                                modifier_keys = [ "SUPER" ];
                                key_symbol = "b";
                                mangowc_command = "spawn";
                                command_arguments = "vivaldi";
                              };
                            };
                          }
                        '';
                        type = lib.types.attrsOf keybind_submodule;
                      };

                      settings = lib.mkOption {
                        default = { };
                        description = "Raw MangoWC settings written as key=value pairs.";
                        example = lib.literalExpression ''
                          {
                            eiros.users.alice.mangowc.settings = { border_width = 2; gaps_in = 5; };
                          }
                        '';
                        type = lib.types.attrsOf (
                          lib.types.oneOf [
                            lib.types.str
                            lib.types.int
                            (lib.types.listOf lib.types.str)
                          ]
                        );
                      };
                    };
                  }
                );
              };
            };
          }
        )
      );
    };
  };

  config = {
    warnings = lib.flatten (
      lib.mapAttrsToList (
        username: user_config:
        lib.optional (user_config.initial_password == username)
          "User '${username}' has initial_password set to their username — change this before deploying to a real system."
      ) config.eiros.users
    );

    assertions = lib.flatten (
      lib.mapAttrsToList (
        username: user_config:
        (lib.optional
          (user_config.mangowc != null && !config.eiros.system.desktop_environment.mangowc.enable)
          {
            assertion = false;
            message = "User '${username}' has mangowc config but eiros.system.desktop_environment.mangowc.enable is false.";
          })
      ) config.eiros.users
    );

    users.users = lib.mapAttrs (username: user_config: {
      description = lib.mkDefault username;
      extraGroups = lib.mkDefault user_config.extra_groups;
      initialPassword = lib.mkDefault user_config.initial_password;
      isNormalUser = lib.mkDefault true;
    }) config.eiros.users;

    hjem.users = lib.mapAttrs (
      username: user_config:
      let
        mangowc_cfg = user_config.mangowc;
        mangowc_enabled = config.eiros.system.desktop_environment.mangowc.enable && mangowc_cfg != null;
        dms_cfg = user_config.dms;
        dms_enabled = config.eiros.system.desktop_environment.dankmaterialshell.enable && dms_cfg != null;
      in
      {
        directory = lib.mkDefault "/home/${username}";
        user = username;

        files =
          (lib.optionalAttrs mangowc_enabled {
            ".config/mango/config.conf" = {
              clobber = lib.mkDefault mangowc_cfg.clobber_home_directory;
              generator = mangowc_generator;
              value = make_user_mangowc_config mangowc_cfg;
            };
          })
          // (lib.optionalAttrs dms_enabled {
            ".config/DankMaterialShell/settings.json" = {
              clobber = lib.mkDefault dms_cfg.clobber;
              text = builtins.toJSON dms_cfg.settings;
            };
            ".config/DankMaterialShell/plugin_settings.json" = {
              clobber = lib.mkDefault dms_cfg.clobber;
              text = builtins.toJSON dms_cfg.plugin_settings;
            };
          });
      }
    ) config.eiros.users;
  };
}

# Serializes structured MangoWC keybind declarations into key=value config file lines.
lib:
let
  to_string_list =
    v:
    if v == null then
      [ ]
    else if lib.isList v then
      map toString v
    else
      [ (toString v) ];

  make_bind_line =
    kb:
    let
      modifier_keys_str = if kb.modifier_keys == [ ] then "none" else lib.concatStringsSep "+" kb.modifier_keys;
      command_args_str = if kb.command_arguments == null then "" else kb.command_arguments;
    in
    "${modifier_keys_str},${kb.key_symbol},${kb.mangowc_command},${command_args_str}";

  make_mangowc_config =
    mangowc_cfg:
    let
      extra_bind_attrs = builtins.foldl' (
        acc: kb:
        let
          flags_str = lib.concatStrings (kb.flag_modifiers or [ ]);
          bind_key = "bind" + flags_str;
          line = make_bind_line kb;
          previous = acc.${bind_key} or [ ];
        in
        acc // { ${bind_key} = previous ++ [ line ]; }
      ) { } (lib.attrValues mangowc_cfg.keybinds);
    in
    mangowc_cfg.settings
    // lib.mapAttrs (
      name: lines: (to_string_list (mangowc_cfg.settings.${name} or [ ])) ++ lines
    ) extra_bind_attrs;
in
{
  inherit to_string_list make_bind_line make_mangowc_config;

  mangowc_generator = lib.generators.toKeyValue {
    mkKeyValue =
      name: value:
      if lib.isList value then
        lib.concatMapStringsSep "\n" (v: "${name}=${toString v}") value
      else
        "${name}=${toString value}";
  };

  keybind_submodule = lib.types.submodule (
    { ... }:
    {
      options = {
        command_arguments = lib.mkOption {
          default = null;
          description = "Optional command arguments.";
          example = "vivaldi";
          type = lib.types.nullOr lib.types.str;
        };

        flag_modifiers = lib.mkOption {
          default = [ ];
          description = "MangoWC bind flags: l (lock), r (release), s (keysym).";
          example = [ "l" "s" ];
          type = lib.types.listOf (lib.types.enum [ "l" "r" "s" ]);
        };

        key_symbol = lib.mkOption {
          description = "Key symbol such as \"Return\", \"Q\", or \"space\".";
          example = "Return";
          type = lib.types.str;
        };

        mangowc_command = lib.mkOption {
          description = "MangoWC command (e.g., \"spawn\", \"killclient\", \"quit\").";
          example = "spawn";
          type = lib.types.str;
        };

        modifier_keys = lib.mkOption {
          default = [ ];
          description = "Modifier keys joined using '+', e.g., [\"SUPER\" \"SHIFT\"].";
          example = [ "SUPER" "SHIFT" ];
          type = lib.types.listOf lib.types.str;
        };
      };
    }
  );
}

# Configures CPU vendor detection, microcode updates, and IOMMU kernel parameters.
{ config, lib, ... }:
let
  eiros_cpu = config.eiros.system.hardware.cpu;

  vendor_is_set = eiros_cpu.vendor != null;
in
{
  options.eiros.system.hardware.cpu = {
    iommu.enable = lib.mkOption {
      default = false;
      description = "Enable IOMMU (intel_iommu=on or amd_iommu=on). Required for KVM DMA isolation and effective use of iommu=pt. Requires vendor to be set.";
      example = lib.literalExpression ''
        {
          eiros.system.hardware.cpu.iommu.enable = true;
        }
      '';
      type = lib.types.bool;
    };

    microcode.enable = lib.mkOption {
      default = true;
      description = "Enable CPU microcode updates.";
      example = lib.literalExpression ''
        {
          eiros.system.hardware.cpu.microcode.enable = false;
        }
      '';
      type = lib.types.bool;
    };

    vendor = lib.mkOption {
      default = null;
      description = "CPU vendor. If null, enable microcode updates for both AMD and Intel.";
      example = lib.literalExpression ''
        {
          eiros.system.hardware.cpu.vendor = "intel";
        }
      '';
      type = lib.types.nullOr (
        lib.types.enum [
          "amd"
          "intel"
        ]
      );
    };
  };

  config = {
    assertions = [
      {
        assertion = !eiros_cpu.iommu.enable || vendor_is_set;
        message = "eiros.system.hardware.cpu.iommu.enable requires vendor to be set to \"amd\" or \"intel\".";
      }
    ];

    warnings = lib.optionals (eiros_cpu.microcode.enable && !vendor_is_set) [
      "eiros.system.hardware.cpu.vendor is null; enabling microcode updates for both AMD and Intel."
    ];

    boot.kernelParams = lib.optionals (eiros_cpu.iommu.enable && vendor_is_set) [
      (if eiros_cpu.vendor == "intel" then "intel_iommu=on" else "amd_iommu=on")
    ];

    hardware = {
      cpu = lib.mkMerge [
        (lib.mkIf (eiros_cpu.vendor == "amd" || !vendor_is_set) {
          amd = {
            updateMicrocode = eiros_cpu.microcode.enable;
          };
        })

        (lib.mkIf (eiros_cpu.vendor == "intel" || !vendor_is_set) {
          intel = {
            updateMicrocode = eiros_cpu.microcode.enable;
          };
        })
      ];
    };
  };
}

# Configures NVIDIA/Mesa GPU drivers, 32-bit support, and PRIME hybrid graphics.
{
  config,
  lib,
  pkgs,
  ...
}:
let
  eiros_graphics = config.eiros.system.hardware.graphics;
  eiros_nvidia = eiros_graphics.nvidia;

  nvidia_enabled = eiros_graphics.enable && eiros_nvidia.enable;

  prime_enabled = nvidia_enabled && eiros_nvidia.prime.enable;
  prime_offload_enabled = prime_enabled && eiros_nvidia.prime.offload.enable;
  prime_sync_enabled = prime_enabled && eiros_nvidia.prime.sync.enable;
in
{
  options.eiros.system.hardware.graphics = {
    enable = lib.mkOption {
      default = true;
      description = "Enable Eiros hardware graphics.";
      example = lib.literalExpression ''
        {
          eiros.system.hardware.graphics.enable = false;
        }
      '';
      type = lib.types.bool;
    };

    bits_32 = {
      enable = lib.mkOption {
        default = true;
        description = "Enable 32-bit graphics libraries (for 32-bit applications).";
        example = lib.literalExpression ''
          {
            eiros.system.hardware.graphics.bits_32.enable = false;
          }
        '';
        type = lib.types.bool;
      };
    };

    nvidia = {
      enable = lib.mkOption {
        default = true;
        description = "Enable NVIDIA GPU support.";
        example = lib.literalExpression ''
          {
            eiros.system.hardware.graphics.nvidia.enable = false;
          }
        '';
        type = lib.types.bool;
      };

      container_toolkit = {
        enable = lib.mkOption {
          default = true;
          description = "Enable NVIDIA Container Toolkit (for GPU support in containers).";
          example = lib.literalExpression ''
            {
              eiros.system.hardware.graphics.nvidia.container_toolkit.enable = false;
            }
          '';
          type = lib.types.bool;
        };
      };

      open.enable = lib.mkOption {
        default = true;
        description = "Enable the NVIDIA open kernel module (hardware.nvidia.open).";
        example = lib.literalExpression ''
          {
            eiros.system.hardware.graphics.nvidia.open.enable = false;
          }
        '';
        type = lib.types.bool;
      };

      settings = {
        enable = lib.mkOption {
          default = true;
          description = "Install the nvidia-settings GUI tool.";
          example = lib.literalExpression ''
            {
              eiros.system.hardware.graphics.nvidia.settings.enable = false;
            }
          '';
          type = lib.types.bool;
        };
      };

      prime = {
        enable = lib.mkOption {
          default = false;
          description = "Enable NVIDIA PRIME (hybrid graphics) configuration.";
          example = lib.literalExpression ''
            {
              eiros.system.hardware.graphics.nvidia.prime.enable = true;
            }
          '';
          type = lib.types.bool;
        };

        intel_bus_id = lib.mkOption {
          default = null;
          description = "Intel iGPU PCI Bus ID (e.g. \"PCI:0:2:0\"). Required when PRIME is enabled.";
          example = lib.literalExpression ''
            {
              eiros.system.hardware.graphics.nvidia.prime.intel_bus_id = "PCI:0:2:0";
            }
          '';
          type = lib.types.nullOr lib.types.str;
        };

        nvidia_bus_id = lib.mkOption {
          default = null;
          description = "NVIDIA dGPU PCI Bus ID (e.g. \"PCI:1:0:0\"). Required when PRIME is enabled.";
          example = lib.literalExpression ''
            {
              eiros.system.hardware.graphics.nvidia.prime.nvidia_bus_id = "PCI:1:0:0";
            }
          '';
          type = lib.types.nullOr lib.types.str;
        };

        offload.enable = lib.mkOption {
          default = true;
          description = "Enable PRIME render offload (recommended default for laptops).";
          example = lib.literalExpression ''
            {
              eiros.system.hardware.graphics.nvidia.prime.offload.enable = false;
            }
          '';
          type = lib.types.bool;
        };

        sync.enable = lib.mkOption {
          default = false;
          description = "Enable PRIME sync (use instead of offload).";
          example = lib.literalExpression ''
            {
              eiros.system.hardware.graphics.nvidia.prime.sync.enable = true;
            }
          '';
          type = lib.types.bool;
        };
      };

      power_management = {
        enable = lib.mkOption {
          default = true;
          description = "Enable NVIDIA power management (sets NVreg_PreserveVideoMemoryAllocations=1). Prevents the driver from reclaiming GPU memory allocations, improving Wayland rendering stability.";
          example = lib.literalExpression ''
            {
              eiros.system.hardware.graphics.nvidia.power_management.enable = false;
            }
          '';
          type = lib.types.bool;
        };
      };

      wayland = {
        wlr_no_hardware_cursors.enable = lib.mkOption {
          default = true;
          description = "Set WLR_NO_HARDWARE_CURSORS=1 (wlroots cursor workaround).";
          example = lib.literalExpression ''
            {
              eiros.system.hardware.graphics.nvidia.wayland.wlr_no_hardware_cursors.enable = false;
            }
          '';
          type = lib.types.bool;
        };
      };
    };
  };

  config = lib.mkIf eiros_graphics.enable {
    assertions = [
      {
        assertion = !nvidia_enabled || (config.nixpkgs.config.allowUnfree or false);
        message = "NVIDIA support is enabled, but nixpkgs.config.allowUnfree is false; NVIDIA drivers may be unavailable.";
      }
      {
        assertion =
          !prime_enabled
          || (eiros_nvidia.prime.intel_bus_id != null && eiros_nvidia.prime.nvidia_bus_id != null);
        message = "NVIDIA PRIME is enabled; set eiros.system.hardware.graphics.nvidia.prime.intel_bus_id and .nvidia_bus_id.";
      }
      {
        assertion = !(prime_offload_enabled && prime_sync_enabled);
        message = "NVIDIA PRIME: offload and sync cannot both be enabled; choose one.";
      }
      {
        assertion =
          eiros_nvidia.prime.intel_bus_id == null
          || lib.match "PCI:[0-9]+:[0-9]+:[0-9]+" eiros_nvidia.prime.intel_bus_id != null;
        message = "eiros.system.hardware.graphics.nvidia.prime.intel_bus_id must be in 'PCI:X:Y:Z' format (e.g. \"PCI:0:2:0\").";
      }
      {
        assertion =
          eiros_nvidia.prime.nvidia_bus_id == null
          || lib.match "PCI:[0-9]+:[0-9]+:[0-9]+" eiros_nvidia.prime.nvidia_bus_id != null;
        message = "eiros.system.hardware.graphics.nvidia.prime.nvidia_bus_id must be in 'PCI:X:Y:Z' format (e.g. \"PCI:1:0:0\").";
      }
    ];

    environment = {
      variables = lib.mkIf nvidia_enabled (
        # GBM_BACKEND and __GLX_VENDOR_LIBRARY_NAME must not be set globally in PRIME
        # offload mode; they would force all rendering through NVIDIA even for iGPU clients.
        (lib.optionalAttrs (!prime_offload_enabled) {
          GBM_BACKEND = "nvidia-drm";
          __GLX_VENDOR_LIBRARY_NAME = "nvidia";
          __GL_VRR_ALLOWED = "0";
        })
        // (lib.optionalAttrs eiros_nvidia.wayland.wlr_no_hardware_cursors.enable {
          WLR_NO_HARDWARE_CURSORS = "1";
        })
      );
    };

    hardware = {
      graphics = {
        enable = true;

        enable32Bit = eiros_graphics.bits_32.enable;

        extraPackages = lib.optionals nvidia_enabled [
          pkgs.egl-wayland
          pkgs.nvidia-vaapi-driver
        ];
      };

      nvidia = lib.mkIf nvidia_enabled (
        {
          modesetting = {
            enable = true;
          };

          powerManagement = {
            enable = eiros_nvidia.power_management.enable;
          };

          nvidiaSettings = eiros_nvidia.settings.enable;
          open = eiros_nvidia.open.enable;
        }
        // (lib.optionalAttrs prime_enabled {
          prime = {
            intelBusId = eiros_nvidia.prime.intel_bus_id;
            nvidiaBusId = eiros_nvidia.prime.nvidia_bus_id;

            offload = {
              enable = eiros_nvidia.prime.offload.enable;
              enableOffloadCmd = eiros_nvidia.prime.offload.enable;
            };

            sync = {
              enable = eiros_nvidia.prime.sync.enable;
            };
          };
        })
      );

      nvidia-container-toolkit = lib.mkIf (nvidia_enabled && eiros_nvidia.container_toolkit.enable) {
        enable = true;
      };
    };

    services = {
      xserver = {
        videoDrivers = lib.mkIf nvidia_enabled [ "nvidia" ];
      };
    };
  };
}

